"""Repo-local state paths for the zhanla CLI."""
from __future__ import annotations

from pathlib import Path

STATE_DIR_NAME = ".zhanla"
_LEGACY_STATE_DIR_NAME = ".benchmark"
_LEGACY_STATE_FILES = ("credentials.json", "version_cache.json")
_STATE_GITIGNORE_ENTRY = f"/{STATE_DIR_NAME}/"
_STATE_GITIGNORE_PATTERNS = {
    STATE_DIR_NAME,
    f"{STATE_DIR_NAME}/",
    f"/{STATE_DIR_NAME}",
    _STATE_GITIGNORE_ENTRY,
}
_PROJECT_MARKERS = (
    "pyproject.toml",
    "package.json",
    "requirements.txt",
    "setup.py",
    "setup.cfg",
    "tsconfig.json",
)


def find_repo_root(start_dir: str | Path | None = None) -> Path:
    """Resolve the current repo/project root for CLI state.

    Prefer the nearest ancestor containing `.git`. If no git root is present,
    fall back to the nearest ancestor containing a common project marker.
    Otherwise use the current working directory.
    """
    directory = Path(start_dir or Path.cwd()).resolve()

    for parent in [directory, *directory.parents]:
        if (parent / ".git").exists():
            return parent

    for parent in [directory, *directory.parents]:
        if any((parent / marker).exists() for marker in _PROJECT_MARKERS):
            return parent

    return directory


def get_state_dir(start_dir: str | Path | None = None) -> Path:
    """Return the repo-local directory used for CLI state."""
    return find_repo_root(start_dir) / STATE_DIR_NAME


def get_legacy_global_state_dir(home_dir: str | Path | None = None) -> Path:
    """Return the legacy user-home state directory used by older CLI versions."""
    if home_dir is None:
        return Path.home() / _LEGACY_STATE_DIR_NAME
    return Path(home_dir).resolve() / _LEGACY_STATE_DIR_NAME


def get_legacy_repo_state_dir(start_dir: str | Path | None = None) -> Path:
    """Return the legacy repo-local state directory used by earlier CLI versions."""
    return find_repo_root(start_dir) / _LEGACY_STATE_DIR_NAME


def _cleanup_legacy_dir(legacy_dir: Path) -> bool:
    """Best-effort removal of managed files from one legacy state directory."""
    removed_any = False
    try:
        if not legacy_dir.is_dir():
            return False
    except OSError:
        return False

    for filename in _LEGACY_STATE_FILES:
        candidate = legacy_dir / filename
        try:
            if candidate.is_file() or candidate.is_symlink():
                candidate.unlink()
                removed_any = True
        except OSError:
            pass

    try:
        next(legacy_dir.iterdir())
    except StopIteration:
        try:
            legacy_dir.rmdir()
            # Only count as a meaningful cleanup if we actually removed managed files.
            # Removing an already-empty dir (e.g. created manually) shouldn't trigger
            # the migration notice.
        except OSError:
            pass
    except OSError:
        pass

    return removed_any


def cleanup_legacy_state(
    start_dir: str | Path | None = None,
    home_dir: str | Path | None = None,
) -> bool:
    """Best-effort removal of legacy `.benchmark` CLI state.

    Older CLI versions stored state in `.benchmark`. Newer versions use
    `.zhanla`, so remove the known legacy files from both the repo root and the
    user's home directory, then drop those directories if they become empty.
    """
    cleaned_repo_state = _cleanup_legacy_dir(get_legacy_repo_state_dir(start_dir))
    cleaned_global_state = _cleanup_legacy_dir(get_legacy_global_state_dir(home_dir))
    return cleaned_repo_state or cleaned_global_state


def ensure_state_dir_ready(state_dir: str | Path) -> None:
    """Create the repo-local state dir and keep it out of git by default."""
    directory = Path(state_dir)
    directory.mkdir(parents=True, exist_ok=True)

    if directory.name != STATE_DIR_NAME:
        return

    gitignore_path = directory.parent / ".gitignore"
    try:
        existing = gitignore_path.read_text() if gitignore_path.exists() else ""
    except OSError:
        return

    if any(line.strip() in _STATE_GITIGNORE_PATTERNS for line in existing.splitlines()):
        return

    prefix = "" if not existing or existing.endswith("\n") else "\n"
    try:
        gitignore_path.write_text(f"{existing}{prefix}{_STATE_GITIGNORE_ENTRY}\n")
    except OSError:
        pass


def get_credentials_path(start_dir: str | Path | None = None) -> Path:
    """Return the repo-local credentials file path."""
    return get_state_dir(start_dir) / "credentials.json"


def get_version_cache_path(start_dir: str | Path | None = None) -> Path:
    """Return the repo-local update cache path."""
    return get_state_dir(start_dir) / "version_cache.json"
